97	function truncatePlain(text: string, width: number): string {
98	  if (text.length <= width) return text;
99	  if (width <= 1) return text.slice(0, Math.max(0, width));
100	  return `${text.slice(0, width - 1)}…`;
101	}
102	
103	function centerPlain(text: string, width: number): string {
104	  const truncated = truncatePlain(text, width);
105	  const gap = Math.max(0, width - truncated.length);
106	  const left = Math.floor(gap / 2);
107	  return `${" ".repeat(left)}${truncated}${" ".repeat(gap - left)}`;
108	}
109	
110	function wrapWords(text: string, maxWidth: number): string[] {
111	  const width = Math.max(1, maxWidth);
112	  const words = text.split(/\s+/).filter(Boolean);
113	  const lines: string[] = [];
114	  let current = "";
115	
116	  for (const raw of words) {
117	    const word = truncatePlain(raw, width);
118	    const next = current ? `${current} ${word}` : word;
119	    if (current && next.length > width) {
120	      lines.push(current);
121	      current = word;
122	    } else {
123	      current = next;
124	    }
125	  }
126	
127	  if (current) lines.push(current);
128	  return lines.length > 0 ? lines : [""];
129	}
