158	function summarizeLastActivity(ctx: any): string {
159	  const branch = ctx?.sessionManager?.getBranch?.();
160	  if (!Array.isArray(branch)) return "";
161	
162	  for (let index = branch.length - 1; index >= 0; index -= 1) {
163	    const entry = branch[index];
164	    if (entry?.type !== "message") continue;
165	    const message = entry.message;
166	    const role = message?.role === "assistant" ? "agent" : message?.role === "user" ? "you" : message?.role;
167	    const content = message?.content;
168	    const text = typeof content === "string"
169	      ? content
170	      : Array.isArray(content)
171	        ? content.map((item: any) => item?.text ?? (item?.name ? `[${item.name}]` : "")).filter(Boolean).join(" ")
172	        : "";
173	    const compact = text.replace(/\s+/g, " ").trim();
174	    if (compact) return `${role ?? "message"}: ${compact}`;
175	  }
176	
177	  return "";
178	}
