526	  pi.registerCommand("threads", {
527	    description: "List threads or switch to one by ID.",
528	    handler: async (args: string[], ctx: any) => {
529	      const id = textFromArgs(args);
530	      if (!id) {
531	        const threads = await threadList(ctx.cwd);
532	        if (threads.length === 0) {
533	          notify(ctx, "No threads yet.");
534	          return;
535	        }
536	        for (const t of threads) {
537	          notify(ctx, `${t.id} ${t.status} ${t.title}`);
538	        }
539	        return;
540	      }
541	      await threadSwitch(ctx.cwd, id);
542	      notify(ctx, `Switched to thread: ${id}`);
543	    }
544	  });
545	
546	  pi.registerCommand("rollback", {
547	    description: "Rollback a file to a previous version.",
548	    handler: async (args: string[], ctx: any) => {
549	      const parts = (Array.isArray(args) ? args : String(args ?? "").split(/\s+/));
550	      const path = parts[0];
551	      if (!path) {
552	        notify(ctx, "Usage: /rollback <path> [steps]");
553	        return;
554	      }
555	      const steps = parts[1] ? parseInt(parts[1], 10) : 1;
556	      const result = await fileRollback(ctx.cwd, path, steps);
557	      notify(ctx, result.ok ? `OK: ${result.message}` : `FAIL: ${result.message}`);
558	    }
559	  });
560	
561	  pi.registerCommand("decomp", {
562	    description: "Decompose a task into subtasks using the decomposition planner.",
563	    handler: async (args: string[], ctx: any) => {
564	      const task = textFromArgs(args);
565	      if (!task) {
566	        notify(ctx, "Usage: /decomp <task>");
567	        return;
568	      }
569	      const { subtasks, patternId } = await runDecomposition(ctx.cwd, task, classifyTask(task));
570	      notify(ctx, `pattern=${patternId} type=${classifyTask(task)} subtasks=${subtasks.length}`);
571	      for (const s of subtasks) {
572	        notify(ctx, `  [${s.dependencies.join(",")}] ${s.profileHint}: ${s.description}`);
573	      }
574	    }
575	  });
576	
577	  pi.registerCommand("stores", {
578	    description: "List dynamic stores or filter by namespace.",
579	    handler: async (args: string[], ctx: any) => {
580	      const ns = textFromArgs(args) || undefined;
581	      const specs = await storeList(ctx.cwd, ns ? { namespace: ns } : undefined);
582	      if (specs.length === 0) {
583	        notify(ctx, "No dynamic stores. Use /store create to make one.");
584	        return;
585	      }
586	      for (const s of specs) {
587	        notify(ctx, `${s.namespace}/${s.name} (${s.kind}) — ${s.description || "no description"}`);
588	      }
589	    }
590	  });
591	
592	  pi.registerCommand("stores", {
593	    description: "List or manage dynamic stores.",
594	    handler: async (args: string[], ctx: any) => {
595	      const parts = Array.isArray(args) ? args : String(args ?? "").split(/\s+/);
596	      const [sub, name, ...rest] = parts;
597	      if (!sub) {
598	        const specs = await storeList(ctx.cwd);
599	        if (specs.length === 0) {
600	          notify(ctx, "No stores yet.");
601	          return;
602	        }
603	        for (const s of specs) {
604	          notify(ctx, `${s.namespace ? s.namespace + "/" : ""}${s.name} (${s.kind})`);
605	        }
606	        return;
607	      }
608	      try {
609	        switch (sub) {
610	          case "create": {
611	            const [kind, ns, ...descParts] = rest;
612	            if (!name || !kind) { notify(ctx, "Usage: /stores create <name> <kv|log|set|counter> [namespace] [description]"); return; }
613	            const spec = await storeCreate(ctx.cwd, name, kind as any, { namespace: ns || undefined, description: descParts.join(" ") || undefined });
614	            notify(ctx, `Created ${spec.namespace}/${spec.name} (${spec.kind})`);
615	            return;
616	          }
617	          case "delete": {
618	            const [ns] = rest;
619	            notify(ctx, await storeDelete(ctx.cwd, name, ns || undefined));
620	            return;
621	          }
622	          case "get": {
623	            const [field, ns] = rest;
624	            if (!field) { notify(ctx, "Usage: /stores get <name> <field> [namespace]"); return; }
625	            notify(ctx, await storeGet(ctx.cwd, name, field, ns || undefined));
626	            return;
627	          }
628	          case "set": {
629	            const [field, value, ns] = rest;
630	            if (!field || value === undefined) { notify(ctx, "Usage: /stores set <name> <field> <value> [namespace]"); return; }
631	            notify(ctx, await storeSet(ctx.cwd, name, field, value, ns || undefined));
632	            return;
633	          }
634	          case "rm": {
635	            const [field, ns] = rest;
636	            if (!field) { notify(ctx, "Usage: /stores rm <name> <field> [namespace]"); return; }
637	            notify(ctx, await storeRemove(ctx.cwd, name, field, ns || undefined));
638	            return;
639	          }
640	          case "dump": {
641	            const [ns] = rest;
642	            notify(ctx, await storeDump(ctx.cwd, name, ns || undefined));
643	            return;
644	          }
645	          default:
646	            notify(ctx, `Unknown store subcommand: ${sub}`);
647	        }
648	      } catch (err) {
649	        notify(ctx, `Error: ${err instanceof Error ? err.message : String(err)}`);
650	      }
651	    }
652	  });
653	
654	  pi.on("session_start", async (_event: any, ctx: any) => {
655	    globalToolRegistry.setCwd(ctx.cwd);
656	
657	    const state = await loadProfileState(ctx.cwd);
658	    const evolution = await loadEvolutionState(ctx.cwd);
659	    const toolCount = ALL_TOOL_GROUPS.reduce((n, g) => n + g.definitions.length, 0);
660	    if (!welcomeShown) {
661	      welcomeShown = true;
662	      if (ctx.hasUI !== false && typeof ctx.ui.setHeader === "function") {
663	        ctx.ui.setHeader(createChrysalisWelcomeComponent(pi, ctx, state, evolution));
664	      } else if (typeof ctx.ui.setWidget === "function") {
665	        ctx.ui.setWidget("chrysalis-welcome", createChrysalisWelcomeComponent(pi, ctx, state, evolution));
666	      }
667	    }
668	    notify(
669	      ctx,
670	      `Chrysalis loaded. ${toolCount} LLM tools registered. Active profile: ${state.activeProfile}.`
671	    );
672	    for (const line of summarizeEvolutionState(evolution)) {
673	      notify(ctx, line);
674	    }
675	    void runAutonomousEvolution(ctx.cwd, { kind: "session_start", profile: state.activeProfile }).then((report) => {
676	      if (report.applied) {
677	        notify(ctx, `Autonomous evolution applied: ${report.decision.reason}`);
678	      }
679	    });
680	
681	    globalToolRegistry.on("tool:evolved", ({ name, variant, rejected }: any) => {
682	      notify(ctx, `Tool '${name}' evolved: novelty=${variant.noveltyScore?.toFixed(2)} ${rejected ? "(low novelty)" : "(active)"}`);
683	    });
684	    globalToolRegistry.on("tool:enabled", ({ name }: any) => {
685	      notify(ctx, `Tool '${name}' enabled`);
686	    });
687	    globalToolRegistry.on("tool:disabled", ({ name }: any) => {
688	      notify(ctx, `Tool '${name}' disabled`);
689	    });
690	    globalToolRegistry.on("tool:variant-selected", ({ name, variantId }: any) => {
691	      notify(ctx, `Tool '${name}' variant ${variantId} selected`);
692	    });
693	  });
694	}
