1	import { readFile, writeFile } from "node:fs/promises";
2	import { mkdir } from "node:fs/promises";
3	import { join, resolve } from "node:path";
4	
5	const DEFAULT_TTL = 86400;
6	const MAX_CACHE_TTL = 604800;
7	
8	interface CacheEntry {
9	  value: string;
10	  createdAt: number;
11	  ttl: number;
12	  tags: string[];
13	}
14	
15	function cacheStorePath(cwd: string, rootName = ".chrysalis"): string {
16	  return join(resolve(cwd, rootName), "state", "web-cache.json");
17	}
18	
19	async function ensureCacheDir(cwd: string, rootName = ".chrysalis"): Promise<void> {
20	  await mkdir(join(resolve(cwd, rootName), "state"), { recursive: true });
21	}
22	
23	async function loadCache(cwd: string): Promise<Record<string, CacheEntry>> {
24	  await ensureCacheDir(cwd);
25	  try {
26	    return JSON.parse(await readFile(cacheStorePath(cwd), "utf8")) as Record<string, CacheEntry>;
27	  } catch {
28	    return {};
29	  }
30	}
31	
32	async function saveCache(cwd: string, cache: Record<string, CacheEntry>): Promise<void> {
33	  await ensureCacheDir(cwd);
34	  await writeFile(cacheStorePath(cwd), `${JSON.stringify(cache, null, 2)}\n`, "utf8");
35	}
36	
37	async function cacheGet(cwd: string, key: string): Promise<string | null> {
38	  const cache = await loadCache(cwd);
39	  const entry = cache[key];
40	  if (!entry) return null;
41	  if (Date.now() / 1000 > entry.createdAt + entry.ttl) {
42	    delete cache[key];
43	    await saveCache(cwd, cache);
44	    return null;
45	  }
46	  return entry.value;
47	}
48	
49	async function cacheSetWithTags(cwd: string, key: string, value: string, ttl: number, tags: string[]): Promise<void> {
50	  const cache = await loadCache(cwd);
51	  cache[key] = { value, createdAt: Math.floor(Date.now() / 1000), ttl: Math.min(ttl, MAX_CACHE_TTL), tags };
52	  await saveCache(cwd, cache);
53	}
54	
55	export const WEB_TOOL_DEFINITIONS = [
56	  {
57	    name: "web_fetch",
58	    description: "Fetch content from a URL. Returns the response body as text. Supports HTTP/HTTPS. Results are cached with TTL.",
59	    parameters: {
60	      type: "object",
61	      properties: {
62	        url: { type: "string", description: "URL to fetch" },
63	        method: { type: "string", description: "HTTP method (default GET)" },
64	        headers: { type: "object", description: "Additional headers as key-value pairs" },
65	        cache_ttl: { type: "integer", description: "Cache TTL in seconds (0 to disable, default 3600)" }
66	      },
67	      required: ["url"]
68	    }
69	  },
70	  {
71	    name: "web_search",
72	    description: "Search the web using the Exa API. Requires EXA_API_KEY environment variable. Returns search results with titles, URLs, and snippets.",
73	    parameters: {
74	      type: "object",
75	      properties: {
76	        query: { type: "string", description: "Search query" },
77	        count: { type: "integer", description: "Number of results (default 5, max 10)" }
78	      },
79	      required: ["query"]
80	    }
81	  }
82	];
83	
84	export async function executeWebTool(
85	  cwd: string,
86	  name: string,
87	  args: Record<string, unknown>
88	): Promise<string> {
89	  switch (name) {
90	    case "web_fetch": {
91	      const url = String(args.url ?? "");
92	      if (!url) return "Error: url is required";
93	
94	      const cacheTtl = Number(args.cache_ttl ?? 3600);
95	      if (cacheTtl > 0) {
96	        const cached = await cacheGet(cwd, `web:${url}`);
97	        if (cached) return cached;
98	      }
99	
100	      try {
101	        const method = String(args.method ?? "GET").toUpperCase();
102	        const headers: Record<string, string> = args.headers && typeof args.headers === "object"
103	          ? Object.fromEntries(Object.entries(args.headers as Record<string, unknown>).map(([k, v]) => [k, String(v)]))
104	          : {};
105	
106	        const response = await fetch(url, {
107	          method,
108	          headers: { "User-Agent": "Chrysalis-Forge/1.0", ...headers },
109	          signal: AbortSignal.timeout(30000)
110	        });
111	
112	        const body = await response.text();
113	        const result = JSON.stringify({ status: response.status, url: response.url, body: body.slice(0, 50000) }, null, 2);
114	
115	        if (cacheTtl > 0) {
116	          await cacheSetWithTags(cwd, `web:${url}`, result, Math.min(cacheTtl, 604800), ["web"]);
117	        }
118	
119	        return result;
120	      } catch (err: any) {
121	        return `Error fetching ${url}: ${err.message}`;
122	      }
123	    }
124	    case "web_search": {
125	      const query = String(args.query ?? "");
126	      if (!query) return "Error: query is required";
127	
128	      const cached = await cacheGet(cwd, `search:${query}`);
129	      if (cached) return cached;
130	
131	      const apiKey = process.env.EXA_API_KEY;
132	      if (!apiKey) {
133	        return "Error: EXA_API_KEY environment variable not set. Set it to enable web search.";
134	      }
135	
136	      const count = Math.min(Number(args.count ?? 5), 10);
137	      try {
138	        const response = await fetch("https://api.exa.ai/search", {
139	          method: "POST",
140	          headers: {
141	            "Content-Type": "application/json",
142	            "x-api-key": apiKey
143	          },
144	          body: JSON.stringify({
145	            query,
146	            numResults: count,
147	            type: "auto",
148	            contents: { text: { maxCharacters: 500 } }
149	          }),
150	          signal: AbortSignal.timeout(30000)
151	        });
152	
153	        const data = await response.json() as any;
154	        const results = (data.results ?? []).map((r: any) => ({
155	          title: r.title,
156	          url: r.url,
157	          snippet: r.text?.slice(0, 500) ?? ""
158	        }));
159	        const result = JSON.stringify(results, null, 2);
160	
161	        await cacheSetWithTags(cwd, `search:${query}`, result, DEFAULT_TTL, ["web", "search"]);
162	
163	        return result;
164	      } catch (err: any) {
165	        return `Error searching: ${err.message}`;
166	      }
167	    }
168	    default:
169	      return `Unknown web tool: ${name}`;
170	  }
171	}
