207	// Optional `@chrysalis/*` tool packages. Each maps to a directory under
208	// `packages/` (for monorepo/local use) and is resolvable as a bare npm
209	// specifier once installed separately.
210	const OPTIONAL_EXTENSION_DIRS: Record<string, string> = {
211	  "@chrysalis/vcs-jj": "vcs-jj",
212	  "@chrysalis/web": "web",
213	  "@chrysalis/cache": "cache",
