218	/** Walk up from this module to the repo root that contains `packages/`. */
219	function findPackagesRoot(): string | null {
220	  let dir = dirname(fileURLToPath(import.meta.url));
221	  for (let i = 0; i < 8; i += 1) {
222	    if (existsSync(join(dir, "packages"))) return dir;
223	    const parent = dirname(dir);
224	    if (parent === dir) break;
225	    dir = parent;
226	  }
227	  return null;
228	}
229	
230	/** Import an optional extension by name, trying local `packages/` then npm. */
231	async function importExtension(name: string): Promise<any | null> {
232	  const subdir = OPTIONAL_EXTENSION_DIRS[name];
233	  const root = findPackagesRoot();
234	  if (subdir && root) {
235	    const candidates = [
236	      join(root, "packages", subdir, "dist", "index.js"),
237	      join(root, "packages", subdir, "ts", "index.ts")
238	    ];
239	    for (const file of candidates) {
240	      if (existsSync(file)) return import(pathToFileURL(file).href);
241	    }
242	  }
243	  // Fall back to bare-specifier resolution (separately installed package).
244	  try {
245	    return await import(name);
246	  } catch {
247	    return null;
248	  }
249	}
